const express = require('express');
const app = express();
const { readFileSync } = require('fs');

// Read the target URL from an environment variable, e.g., TargetUrl in AWS or GOOGLE_APPLICATION_CRON_URL_TARGET in GCP
const targetUrl = process.env.TargetUrl;
if (!targetUrl) {
  console.error('Error: Please provide a target URL as an environment variable.');
  process.exit(1);
}

app.all('*', (req, res) => {
  const options = {
    method: req.method,
    headers: req.headers,
  };

  // If there is a request body, include it as data in the POST options
  if (req.method === 'POST' && req.body) {
    options.data = JSON.stringify(req.body);
  }

  const proxyRequest = require('proxy-agent')();
  const proxyResponse = require('http');

  const targetReq = proxyRequest.request(targetUrl, options, (targetRes) => {
    // Copy all response headers to the original response object
    res.set(targetRes.headers);

    let body = [];
    targetRes.on('data', (chunk) => {
      body.push(chunk);
    });
    targetRes.on('end', () => {
      res.send(Buffer.concat(body));
    });
  });

  proxyRequest.on('error', (e) => {
    console.error(`Error occurred while proxying the request: ${e}`);
    res.status(500).send();
  });

  req.pipe(targetReq);
});

const port = process.env.PORT || 8080;
app.listen(port, () => {
  console.log(`Webhook proxy server started on port ${port}`);
});